CREATE TABLE threads (
  id TEXT PRIMARY KEY,
  created_at INTEGER,
  updated_at INTEGER,
  source TEXT,
  model_provider TEXT,
  cwd TEXT,
  title TEXT,
  tokens_used INTEGER,
  has_user_event INTEGER,
  archived INTEGER,
  git_sha TEXT,
  git_branch TEXT,
  model TEXT,
  reasoning_effort TEXT,
  created_at_ms INTEGER,
  updated_at_ms INTEGER,
  preview TEXT
);

